import type { FormEvent } from "react";
import { useEffect, useState } from "react";
import type { LinksFunction, MetaFunction } from "@remix-run/node";
import { useNavigate } from "@remix-run/react";
import { useAppKit } from "@reown/appkit/react";
import { toast } from "@/utils/toast";
import { useAccount } from "wagmi";
import { useWalletAuth } from "@/hooks/useWalletAuth";
import { Trans, useTranslation } from "@/i18n";
import { useLocalizedPath } from "@/utils/localizedRoute";
import {
  ArrowRightIcon,
  Eyebrow,
  FunnelPage,
  ProgressSteps,
  TrustStrip,
  VideoCard,
} from "@/components/boosted-funnel/FunnelFrame";

const TELEGRAM_REGEX = /^@?[a-zA-Z0-9_]{4,32}$/;
const TURNSTILE_ORIGIN = "https://challenges.cloudflare.com";
const TURNSTILE_SCRIPT_SRC = `${TURNSTILE_ORIGIN}/turnstile/v0/api.js?render=explicit`;
const TURNSTILE_SITE_KEY = import.meta.env.VITE_TURNSTILE_SITE_KEY;

export const meta: MetaFunction = () => [
  { title: "Boosted Distributor Program - Orderly One" },
  {
    name: "description",
    content:
      "Apply to become an Orderly Boosted Distributor and get paid for the builders you bring to Orderly.",
  },
];

export const links: LinksFunction = () => [
  {
    rel: "preconnect",
    href: TURNSTILE_ORIGIN,
    crossOrigin: "anonymous",
  },
];

function normalizeTelegram(value: string) {
  return value.startsWith("@") ? value : `@${value}`;
}

function formatWalletAddress(value: string) {
  if (!value || value.length <= 13) return value;

  return `${value.slice(0, 6)}...${value.slice(-4)}`;
}

export function BoostedDistributorIntro() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const localizedPath = useLocalizedPath();
  const appKit = useAppKit();
  const { address, isConnected } = useAccount();
  const { isAuthenticated, isLoading, login, user, validateToken } =
    useWalletAuth();
  const [isVerifyingWallet, setIsVerifyingWallet] = useState(false);

  const verifiedAddress =
    isAuthenticated && user?.address && address?.toLowerCase() === user.address
      ? user.address
      : null;
  const displayAddress = verifiedAddress || address || "";
  const shortWalletAddress = formatWalletAddress(displayAddress);
  const walletButtonLabel = !isConnected
    ? t("distributor.boostedApplication.connectWallet")
    : isVerifyingWallet || isLoading
      ? t("distributor.boostedApplication.verifyingWallet")
      : verifiedAddress
        ? t("distributor.boostedApplication.walletVerified")
        : t("distributor.boostedApplication.verifyWallet");
  const renderIntroVideoCard = () => (
    <VideoCard
      caption={t("distributor.boostedApplication.introVideoCaption")}
      duration={t("distributor.boostedApplication.introVideoDuration")}
      poster="/distributor/boosted-page-1-external-bd-poster.png"
      title={t("distributor.boostedApplication.introVideoTitle")}
      youtubeId="VOlsWEY1juU"
    />
  );

  useEffect(() => {
    if (!isConnected || !isAuthenticated) return;

    validateToken().catch(error => {
      console.error("Boosted distributor session validation failed:", error);
    });
  }, [isAuthenticated, isConnected, validateToken]);

  useEffect(() => {
    if (!TURNSTILE_SITE_KEY) return;

    const existingScript = document.querySelector<HTMLScriptElement>(
      'script[src^="https://challenges.cloudflare.com/turnstile/v0/api.js"]'
    );
    if (existingScript) return;

    const script = document.createElement("script");
    script.src = TURNSTILE_SCRIPT_SRC;
    script.async = true;
    script.defer = true;
    document.head.appendChild(script);
  }, []);

  const handleWalletAction = async () => {
    if (!isConnected) {
      appKit?.open({ namespace: "eip155", view: "Connect" });
      return;
    }

    if (verifiedAddress) return;

    try {
      setIsVerifyingWallet(true);
      await login();
      toast.success(t("distributor.boostedApplication.walletVerifiedToast"));
    } catch (error) {
      const message =
        error instanceof Error
          ? error.message
          : t("distributor.boostedApplication.tryAgain");
      toast.error(
        t("distributor.boostedApplication.walletVerificationFailed", {
          message,
        })
      );
    } finally {
      setIsVerifyingWallet(false);
    }
  };

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    const form = event.currentTarget;
    if (!form.reportValidity()) return;

    const formData = new FormData(form);
    const name = String(formData.get("name") || "").trim();
    const email = String(formData.get("email") || "")
      .trim()
      .toLowerCase();
    const telegram = String(formData.get("telegram") || "").trim();

    if (!TELEGRAM_REGEX.test(telegram)) {
      toast.error(t("distributor.boostedApplication.invalidTelegram"));
      return;
    }

    const payload = {
      name,
      email,
      telegram: normalizeTelegram(telegram),
      walletAddress: displayAddress || undefined,
      walletVerified: Boolean(verifiedAddress),
      source: "bd_funnel_v2",
      submitted_at: new Date().toISOString(),
    };

    sessionStorage.setItem("bd_step1", JSON.stringify(payload));
    navigate(localizedPath("/distributor/boosted/apply"));
  };

  return (
    <FunnelPage>
      <ProgressSteps current={1} />

      <div className="grid grid-cols-1 items-start gap-9 lg:grid-cols-2 lg:gap-12">
        <section>
          <Eyebrow>{t("distributor.boostedApplication.eyebrow")}</Eyebrow>
          <h1 className="mb-[18px] text-[clamp(36px,5.5vw,64px)] font-medium leading-[1.08] tracking-[-0.03em] font-display">
            <Trans
              i18nKey="distributor.boostedApplication.title"
              components={[
                <span
                  className="text-gradient-brand inline-block -mb-[0.08em] pb-[0.08em]"
                  key="0"
                />,
              ]}
            />
          </h1>
          <p className="mb-9 max-w-[560px] text-lg leading-[1.55] text-(--fg-secondary)">
            {t("distributor.boostedApplication.introLede")}
          </p>

          <section className="block lg:hidden">
            {renderIntroVideoCard()}
          </section>

          <form
            className="flex flex-col gap-[18px]"
            noValidate
            onSubmit={handleSubmit}
          >
            <div className="flex flex-col gap-2">
              <label
                className="text-[13px] font-medium tracking-[0.01em] text-(--fg-secondary)"
                htmlFor="walletAddress"
              >
                {t("distributor.boostedApplication.walletAddress")}{" "}
                <span className="text-xs text-(--fg-placeholder)">
                  {t("distributor.boostedApplication.optional")}
                </span>
              </label>
              <div className="grid grid-cols-1 gap-3 sm:grid-cols-[minmax(0,1fr)_auto]">
                <input
                  className="autofill-dark w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-4 py-3.5 text-sm text-(--fg-primary) transition-colors placeholder:text-(--fg-placeholder) hover:border-(--line-strong) focus:border-(--line-brand) focus:bg-(--bg-surface-secondary) focus:outline-none focus:shadow-[0_0_0_4px_var(--bg-primary-subtle)]"
                  id="walletAddress"
                  placeholder={t(
                    "distributor.boostedApplication.walletPlaceholder"
                  )}
                  readOnly
                  title={displayAddress}
                  type="text"
                  value={shortWalletAddress}
                />
                <button
                  className={`inline-flex min-w-[128px] items-center justify-center gap-2.5 rounded-full px-[22px] py-3.5 text-sm font-medium leading-[1.2] whitespace-nowrap transition-all duration-300 enabled:hover:-translate-y-0.5 enabled:active:translate-y-0 ${
                    verifiedAddress
                      ? "border border-(--line-strong) bg-transparent text-(--fg-primary) enabled:hover:border-(--line-brand) enabled:hover:bg-(--bg-hover)"
                      : "bg-(--bg-primary) text-(--fg-primary) shadow-[0_0_30px_rgba(120,108,255,0.28)] enabled:hover:shadow-[0_0_50px_rgba(188,0,255,0.32)] enabled:hover:brightness-110"
                  } disabled:cursor-not-allowed disabled:opacity-50`}
                  disabled={
                    isLoading || isVerifyingWallet || Boolean(verifiedAddress)
                  }
                  onClick={handleWalletAction}
                  type="button"
                >
                  {walletButtonLabel}
                </button>
              </div>
              <span className="text-xs text-(--fg-placeholder)">
                {t("distributor.boostedApplication.walletHint")}
              </span>
            </div>

            <div className="flex flex-col gap-2">
              <label
                className="text-[13px] font-medium tracking-[0.01em] text-(--fg-secondary)"
                htmlFor="name"
              >
                {t("distributor.boostedApplication.fullName")}{" "}
                <span className="text-(--fg-brand)">*</span>
              </label>
              <input
                autoComplete="name"
                className="autofill-dark w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-4 py-3.5 text-sm text-(--fg-primary) transition-colors placeholder:text-(--fg-placeholder) hover:border-(--line-strong) focus:border-(--line-brand) focus:bg-(--bg-surface-secondary) focus:outline-none focus:shadow-[0_0_0_4px_var(--bg-primary-subtle)]"
                id="name"
                name="name"
                placeholder={t(
                  "distributor.boostedApplication.fullNamePlaceholder"
                )}
                required
                type="text"
              />
            </div>

            <div className="flex flex-col gap-2">
              <label
                className="text-[13px] font-medium tracking-[0.01em] text-(--fg-secondary)"
                htmlFor="email"
              >
                {t("distributor.boostedApplication.email")}{" "}
                <span className="text-(--fg-brand)">*</span>
              </label>
              <input
                autoComplete="email"
                className="autofill-dark w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-4 py-3.5 text-sm text-(--fg-primary) transition-colors placeholder:text-(--fg-placeholder) hover:border-(--line-strong) focus:border-(--line-brand) focus:bg-(--bg-surface-secondary) focus:outline-none focus:shadow-[0_0_0_4px_var(--bg-primary-subtle)]"
                id="email"
                name="email"
                placeholder={t(
                  "distributor.boostedApplication.emailPlaceholder"
                )}
                required
                type="email"
              />
            </div>

            <div className="flex flex-col gap-2">
              <label
                className="text-[13px] font-medium tracking-[0.01em] text-(--fg-secondary)"
                htmlFor="telegram"
              >
                {t("distributor.boostedApplication.telegram")}{" "}
                <span className="text-(--fg-brand)">*</span>
              </label>
              <input
                className="autofill-dark w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-4 py-3.5 text-sm text-(--fg-primary) transition-colors placeholder:text-(--fg-placeholder) hover:border-(--line-strong) focus:border-(--line-brand) focus:bg-(--bg-surface-secondary) focus:outline-none focus:shadow-[0_0_0_4px_var(--bg-primary-subtle)]"
                id="telegram"
                name="telegram"
                placeholder={t(
                  "distributor.boostedApplication.telegramPlaceholder"
                )}
                required
                type="text"
              />
              <span className="text-xs text-(--fg-placeholder)">
                {t("distributor.boostedApplication.telegramHint")}
              </span>
            </div>

            <div className="mt-2 flex flex-col-reverse items-stretch gap-3 sm:flex-row sm:items-center">
              <button
                className="inline-flex w-full items-center justify-center gap-2.5 rounded-full bg-(--bg-primary) px-9 py-4 text-sm font-medium leading-[1.2] whitespace-nowrap text-(--fg-primary) shadow-[0_0_30px_rgba(120,108,255,0.28)] transition-all duration-300 enabled:hover:-translate-y-0.5 enabled:hover:shadow-[0_0_50px_rgba(188,0,255,0.32)] enabled:hover:brightness-110 enabled:active:translate-y-0 disabled:cursor-not-allowed disabled:opacity-50 sm:w-auto"
                type="submit"
              >
                {t("distributor.boostedApplication.continue")}
                <ArrowRightIcon />
              </button>
            </div>
          </form>

          <TrustStrip />
        </section>

        <section className="hidden lg:block">{renderIntroVideoCard()}</section>
      </div>
    </FunnelPage>
  );
}

export default function BoostedDistributorRoute() {
  return <BoostedDistributorIntro />;
}
